          axisPointer: { type: "cross" },
          backgroundColor: "rgba(255,255,255,0.98)",
          borderColor: "#CBD5E1",
          borderWidth: 1,
          textStyle: { color: "#1E293B", fontSize: 12, fontWeight: 700 },
